const raw = $json?.output;

// Récupérer le produit source (pour ne pas perdre pid, images, etc.)
let carrySrc;
try {
  carrySrc = $node["[CJ] 04 - LOOP - Split In Batches (1 by 1)"]?.json;
} catch (e) {
  carrySrc = undefined;
}

const carry = carrySrc
  ? {
      pid: carrySrc.pid ?? null,
      productName: carrySrc.productName ?? null,
      productNameEn: carrySrc.productNameEn ?? null,
      productSku: carrySrc.productSku ?? null,
      productImage: carrySrc.productImage ?? null,
      productWeight: carrySrc.productWeight ?? null,
      categoryName: carrySrc.categoryName ?? null,
      categoryId: carrySrc.categoryId ?? null,
      sellPrice: carrySrc.sellPrice ?? null,
      remark: carrySrc.remark ?? null,
      isFreeShipping: carrySrc.isFreeShipping ?? null,
      isTestProduct: carrySrc.isTestProduct ?? null,
      shippingCountryCodes: carrySrc.shippingCountryCodes ?? null,
    }
  : null;

function reject(reason) {
  return [
    {
      json: {
        is_relevant: false,
        matched_brand: null,
        category_slug: null,
        reason,
        carry,
        raw_output: raw ?? null,
      },
    },
  ];
}

// 1) Si l'AI node renvoie déjà un objet JSON
if (raw && typeof raw === "object") return [{ json: raw }];

// 2) Si output absent / vide / non string => rejet propre (au lieu de throw)
if (typeof raw !== "string" || !raw.trim()) {
  return reject("Videur: output vide ou non-string (réponse IA invalide).");
}

const text = raw.trim();

// 3) Tentative parse direct (si l'output est un JSON pur)
try {
  return [{ json: JSON.parse(text) }];
} catch (e) {}

// 4) Tentative extraction entre { ... } (si texte autour)
const start = text.indexOf("{");
const end = text.lastIndexOf("}");
if (start !== -1 && end !== -1 && end > start) {
  const slice = text.slice(start, end + 1);
  try {
    return [{ json: JSON.parse(slice) }];
  } catch (e) {}
}

// 5) Sinon: rejet propre (le workflow continue)
return reject("Videur: output non-JSON (le modèle a répondu en texte).");

