// 1. Récupération de la réponse IA
const raw = $json.output;
let cleanRaw = raw.replace(/```json/g, "").replace(/```/g, "").trim();
const start = cleanRaw.indexOf("{");
const end = cleanRaw.lastIndexOf("}");
if (start === -1) throw new Error("No JSON found");
const aiData = JSON.parse(cleanRaw.slice(start, end + 1));

// 2. Récupération des données SOURCE FIABLES (CJ Details)
const detailNode = $node["[CJ]_Get_Enrich_Product_Details"];
if (!detailNode || !detailNode.json || !detailNode.json.data) {
    throw new Error("Source CJ Details introuvable !");
}
const cjData = detailNode.json.data;
const cjVariants = cjData.variants || [];

// 3. MAPPING DES CATÉGORIES
const categoryMap = {
    'coques-protections': 1, 'charge-energie': 2, 'audio-son': 3,
    'supports-fixations': 4, 'decoration-goodies': 5, 'autres': 6
};

// 4. CONSTRUCTION INTELLIGENTE DES VARIANTES (On connecte l'IA !)
const aiTranslations = aiData.variant_translations || {};

const cleanVariants = cjVariants.map(v => {
    const originalName = v.variantNameEn || v.variantName || "";

    // On va chercher la belle traduction (Couleur - Modèle) faite par l'IA
    let cleanName = aiTranslations[originalName] || originalName;

    // Nettoyage de secours si l'IA a oublié de traduire cette variante
    if (cleanName === originalName) {
        cleanName = cleanName.replace(/Apple/ig, "").replace(/Phone Case/ig, "").trim();
    }

    return {
        vid: String(v.vid),
        sku: String(v.variantSku),
        name: cleanName,
        price: parseFloat(v.variantSellPrice)
    };
});

// 5. OBJET FINAL (Blindé contre les crashs)
const merged = {
    should_publish: aiData.should_publish || false,
    pid: String(cjData.pid),

    // L'astuce ?. empêche le crash. Si l'IA n'a rien généré, on utilise le titre original CJ.
    title: aiData.product?.title || cjData.productNameEn || "Produit Rejeté",
    slug: aiData.product?.slug || "produit-rejete",
    description: aiData.product?.description || "Aucune description.",
    brand: aiData.product?.brand || "Autres",
    tags: aiData.product?.tags || [],

    images: cjData.productImageSet || [],
    variants: cleanVariants, // Maintenant, les couleurs sont protégées !

    nc_category_id: categoryMap[aiData.category_slug] || 6,
    base_price: cjData.sellPrice,
    ai_quality_notes: aiData.quality_notes || "Aucune note"
};

return { json: merged };

const p = $json;

// --- 1. LA CARTE AU TRÉSOR (UUIDs NocoDB) ---
const CATEGORY_UUIDS = {
  1: "3e40840a-5111-44ef-b264-a75b836b9138", // Coques & protections
  2: "81c1a551-4ce4-40f7-a096-e85fc9f74a71", // Charge & énergie
  3: "64900192-a354-41c1-8f35-a1d13299352e", // Audio & son
  4: "46484275-e161-4bef-8a71-f67d51cb639f", // Supports & fixations
  5: "2070f06d-c3e0-4253-947d-374f8f46368a", // Décoration & goodies
  6: "7167a98a-60dd-4f78-9a56-e206813d4a3c"  // Autres
};

// --- 2. SÉCURISATION & CALCULS ---
const safePrice = parseFloat(p.base_price) || 0;
const aiCategoryNumber = parseInt(p.nc_category_id);
const finalCategoryUUID = CATEGORY_UUIDS[aiCategoryNumber] || CATEGORY_UUIDS[6];

const mainImage = (Array.isArray(p.images) && p.images.length > 0) ? p.images[0] : null;
const tagsArray = Array.isArray(p.tags) ? p.tags : [];
const imagesArray = Array.isArray(p.images) ? p.images : [];

// --- 3. CRÉATION DU PAQUET ---
return [
  {
    json: {
      title: String(p.title || "").substring(0, 255),
      slug: String(p.slug || ""),
      description: String(p.description || ""),
      base_price: safePrice,
      cj_pid: String(p.pid),
      status: "published",
      brand: String(p.brand || "Universel"),
      reference: String(p.sku || `CJ-${p.pid}`),
      image: mainImage,
      images: imagesArray,  
      tags: tagsArray,      
      categories: finalCategoryUUID, // CORRECTION : Virgule ajoutée et nom variable fixé
      ai_feedback: String(p.ai_quality_notes || "RAS"),
      _VARIANTS_READY: (p.variants || []).map(v => ({
          cj_vid: String(v.vid),
          sku: String(v.sku),
          option1_name: "Modèle",
          option1_value: String(v.name),
          price: parseFloat(v.price) || safePrice
      }))
    }
  }
];

// [CJ] 13A - MAP - Prepare Variants
// Objectif : 1 item par variante avec champs utiles + FK produit + valeurs "factorized" robustes

// 1) ID du produit créé (node 13 en input direct)
const createdProduct = $input.first().json;
const productId = createdProduct.Id || createdProduct.id;

if (!productId) {
  throw new Error("Impossible de trouver l'ID du produit créé (Id/id manquant).");
}

// 2) Variantes préparées dans le node 12
const previousData = $node["[CJ] 12 - MAP - Build Product (Published Payload)"].json;
const variantsList = previousData._VARIANTS_READY || [];

// 3) Détails produit/variants (node API) -> 1 seul item, donc OK ici
const apiItem = $node["[CJ]_Get_Enrich_Product_Details"].json;
const details = apiItem?.data || {};
const detailsVariants = Array.isArray(details.variants) ? details.variants : [];
const productImageSet = Array.isArray(details.productImageSet) ? details.productImageSet : [];

function norm(s) {
  return String(s ?? "").replace(/\s+/g, " ").trim();
}

function rightWordSlice(raw, min = 20, max = 35) {
  const s = norm(raw);
  if (!s) return null;
  if (s.length <= max) return s;

  const delims = [" ", "-", "_", "/", "|"];

  const lastDelimBefore = (str, idx) => {
    let best = -1;
    for (const d of delims) {
      const p = str.lastIndexOf(d, idx);
      if (p > best) best = p;
    }
    return best;
  };

  const firstDelimAfter = (str, idx) => {
    for (let i = idx; i < str.length; i++) {
      if (delims.includes(str[i])) return i;
    }
    return -1;
  };

  // coupe à droite sur max, puis ajuste au prochain séparateur pour ne pas couper un mot
  let start = s.length - max;
  const next = firstDelimAfter(s, start);
  if (next !== -1 && (s.length - (next + 1)) >= min) start = next + 1;

  let out = s.slice(start).trim();

  // si trop court, on recule au séparateur précédent (peut dépasser max un peu, accepté)
  if (out.length < min) {
    const start2 = Math.max(0, s.length - min);
    const prev = lastDelimBefore(s, start2);
    if (prev !== -1) out = s.slice(prev + 1).trim();
    else out = s.slice(start2).trim();
  }

  return out || null;
}

function extractTailModel(raw) {
  const s = norm(raw);
  if (!s) return null;

  // 1) iPhone (inclut iPhone16E, iPhone15ProMax, XSmax, XR, X, SE, etc.)
  const rApple =
    /(?:\b(?:iPhone|IPhone|iphone)\b\s*)?(?:(?:\d{1,2}[A-Za-z]?)|(?:XS\s*Max|XSmax|XS|XR|Xr|X|SE|Se))(?:\s*(?:Pro\s*Max|ProMax|Promax|promax|Pro|PRO|Max|MAX|Plus|PLUS|mini|Mini|Air|AIR))?\s*$/;

  // 2) Samsung / Galaxy (générique)
  const rSamsung =
    /(?:\b(?:Samsung|SAMSUNG|samsung|Galaxy|GALAXY|galaxy)\b\s*)?(?:Note\s*)?(?:[SAMZ]\s*)?\d{1,2}(?:\s*(?:Ultra|ULTRA|Plus|PLUS|Pro|PRO|FE|Fe|Lite|LITE|Max|MAX))?\s*$/;

  const m1 = s.match(rApple);
  if (m1 && m1[0]) return m1[0].trim();

  const m2 = s.match(rSamsung);
  if (m2 && m2[0]) return m2[0].trim();

  // 3) fallback robuste (fin de chaîne 20–35 sans couper)
  return rightWordSlice(s, 20, 35);
}

function toNumber(v, fallback = null) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function computeStock(vDet) {
  if (!vDet) return 0;

  // CJ renvoie parfois inventoryNum ou un tableau inventories
  if (vDet.inventoryNum !== null && vDet.inventoryNum !== undefined) {
    return toNumber(vDet.inventoryNum, 0);
  }

  const invs = vDet.inventories;
  if (Array.isArray(invs)) {
    return invs.reduce((sum, i) => sum + (toNumber(i?.inventoryNum, 0) || 0), 0);
  }

  return 0;
}

// 4) Sortie : 1 ligne par variante
return variantsList.map((variant) => {
  const vid = variant.cj_vid ?? variant.vid ?? null;

  // matching sur l'API (sécurisé)
  const vDet =
    detailsVariants.find((x) => String(x?.vid) === String(vid)) || null;

  // champs variant (priorité : ce que tu as déjà, sinon API)
  const imageUrl =
    variant.image_url ||
    variant.variant_image ||
    variant.variantImage ||
    vDet?.variantImage ||
    null;

  const weightGrams =
    variant.weight_grams ??
    vDet?.variantWeight ??
    null;

  const costPrice =
    variant.cost_price ??
    vDet?.variantSellPrice ??
    null;

  const sellPrice =
    variant.price ??
    vDet?.variantSugSellPrice ??
    vDet?.variantSellPrice ??
    null;

  const stockQty =
    variant.stock_quantity ??
    variant.stock ??
    computeStock(vDet);

  // factorized / compact (pour le front)
  const opt1 = variant.option1_value ?? null;
  const opt2 = variant.option2_value ?? null;

  const opt1Factorized = extractTailModel(opt1);
  const opt2Factorized = extractTailModel(opt2);

  return {
    json: {
      // Identifiants variante
      cj_vid: vid,
      sku: variant.sku ?? variant.variantSku ?? null,

      // Options (brutes)
      option1_name: variant.option1_name ?? null,
      option1_value: opt1,
      option2_name: variant.option2_name ?? null,
      option2_value: opt2,

      // Options (compactes / factorisées)
      option1_value_factorized: opt1Factorized,
      option2_value_factorized: opt2Factorized,

      // Données business
      image_url: imageUrl,
      stock_quantity: stockQty,
      weight_grams: weightGrams,
      cost_price: costPrice,
      price: sellPrice,
      compare_at_price: variant.compare_at_price ?? null,

      // Images produit (liste complète)
      images_json: productImageSet.length ? JSON.stringify(productImageSet) : null,

      // FK produit (on remplit les 2 colonnes + relation si tu l’utilises)
      product_uuid: productId,
      product_id: productId,
      products: productId,
    }
  };
});

// 1. Nos 6 pays cibles (Europe + Chine + US)
const pays = ["FR", "DE", "GB", "ES", "CN", "US"];

// 2. Les pages à scanner (1 page = 50 produits). 
// Pour le début de la boutique, mets [1, 2, 3, 4] pour récupérer les 200 derniers produits de chaque catégorie/pays. 
// Plus tard, tu ne laisseras que [1] pour ta routine quotidienne.
const pages_a_scanner = [1]; 

// 3. Ta liste EXACTE et exhaustive
const categories = [
  { nom: "Coques Téléphones", id: "9FA474CF-E06D-4708-AD56-F39FED7F88E3" },
  { nom: "Coques Tablettes", id: "87A618B5-7CB0-4AF7-BCF8-9E9455F06B7E" },
  { nom: "Verres & Films", id: "51D68796-F1B5-4BDC-B9E0-32C3D9FF6994" },
  { nom: "Housses et Pochettes", id: "AD2B299F-EC10-4209-998A-8916AE4D4900" },
  { nom: "Câbles standards", id: "00134C46-B7DF-4500-A3D9-ABB7B779EFD0" },
  { nom: "Câbles Data/Multi", id: "40CC2ED1-8998-4515-9139-787CC25D42A7" },
  { nom: "Chargeurs Muraux", id: "B200FABB-A76B-4750-9957-FEA3DCB21F1F" },
  { nom: "Chargeurs Rapides/Stations", id: "6DB79FAF-593D-4F52-B6FF-AB1D14331862" },
  { nom: "Power Banks", id: "491E5474-524C-4666-BDD7-4E35E38900EA" },
  { nom: "Ecouteurs & Casques", id: "DAECCC3B-13D8-4978-86A8-61D3DF186134" },
  { nom: "Enceintes Portables", id: "C1AB7563-AED4-44D8-9F01-05BD91C65307" },
  { nom: "Micros", id: "8FD4CA46-AA88-4CDC-8EBA-EBD8412152E2" },
  { nom: "Adaptateurs Audio", id: "66D0D817-353B-492E-87A5-024091FF9000" },
  { nom: "Supports & Bagues", id: "9170B3F9-5B9C-4C39-8CD6-7DC00E481D47" },
  { nom: "Trépieds & Ring Lights", id: "11D96803-A0A3-4175-B49B-2102EC285965" },
  { nom: "Objectifs Photo", id: "82643737-E055-4FDF-AD69-4E2C3FB6970B" },
  { nom: "Bijoux & Gadgets", id: "912FD088-248B-4D58-84F7-1F10B888CF8A" },
  { nom: "Accessoires Tablettes Divers", id: "EDC3EDAF-1ED7-4776-8416-E9F8F0A5B4C6" },
