  { nom: "Trackers Bluetooth", id: "B39B6F95-9C89-4D6C-9E98-1633DA6A51CF" }
];

const requetes = [];

// Triple boucle : Pays -> Catégories -> Pages
for (const p of pays) {
  for (const cat of categories) {
    for (const page of pages_a_scanner) {
      requetes.push({
        json: {
          pays_cible: p,
          categorie_id: cat.id,
          categorie_nom: cat.nom,
          numero_page: page
        }
      });
    }
  }
}

return requetes;
